function dec(s){ return String(s).replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#39;/g,"'"); }

function detect(){
  var s = localStorage.getItem('kp_lang');
  if (s === 'zh' || s === 'en') return s;
  return /^en/i.test(navigator.language || '') ? 'en' : 'zh';
}
var LANG = detect();
export function getLang(){ return LANG; }
export function t(key, params){
  var e = DICT[key];
  var s = e ? (e[LANG] != null ? e[LANG] : e.zh) : key;
  if (params) s = String(s).replace(/\{(\w+)\}/g, function(m,p){ return (params && p in params) ? params[p] : m; });
  return s;
}

// ---- reverse map zh -> en (skip code-only + html-body keys) ----
var EXCLUDE = /^(ai\.(sys|gen|greeting|err)|meta\.)|\.html$/;
var ZH2EN = Object.create(null);
for (var k in DICT){
  if (EXCLUDE.test(k)) continue;
  var e = DICT[k];
  if (e && typeof e.zh === 'string' && typeof e.en === 'string' && e.zh.trim().length >= 2) ZH2EN[e.zh.trim()] = dec(e.en);
}
for (var z in OVERLAY){ if (z.trim().length >= 2) ZH2EN[z.trim()] = dec(OVERLAY[z]); }

// ---- placeholder patterns ({n},{title}...) -> regex ----
function esc(s){ return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }
var PATTERNS = [];
for (var zp in ZH2EN){
  if (zp.indexOf('{') < 0) continue;
  if (zp.replace(/\{\w+\}/g,'').trim().length < 2) continue;
  var names = [];
  var body = zp.replace(/\{(\w+)\}/g, function(m,n){ names.push(n); return '\u0000'; });
  var re = '^' + body.split('\u0000').map(esc).join('(.+?)') + '$';
  try { PATTERNS.push({ re: new RegExp(re), names: names, en: ZH2EN[zp] }); } catch(_){}
}
function patternTranslate(str){
  for (var i=0;i<PATTERNS.length;i++){
    var p = PATTERNS[i], mt = str.match(p.re);
    if (mt){ var en = p.en; for (var j=0;j<p.names.length;j++){ en = en.replace(new RegExp('\\{'+p.names[j]+'\\}','g'), mt[j+1]); } return en; }
  }
  return null;
}

var HAS_CJK = /[\u3400-\u9fff\uf900-\ufaff\u3000-\u303f\uff00-\uffef]/;
var origText = new WeakMap();
var SKIP = { SCRIPT:1, STYLE:1, NOSCRIPT:1, TEXTAREA:1 };
var applying = false;

function tText(node, toEn){
  var raw = node.nodeValue; if (!raw) return;
  if (toEn){
    if (!HAS_CJK.test(raw)) return;
    var key = raw.trim(); if (key.length < 2) return;
    var en = ZH2EN[key]; if (en == null) en = patternTranslate(key);
    if (en != null && en !== key){ if (!origText.has(node)) origText.set(node, raw); node.nodeValue = raw.replace(key, en); }
  } else if (origText.has(node)){ node.nodeValue = origText.get(node); origText.delete(node); }
}
var ATTRS = ['placeholder','title','aria-label'];
function tAttrs(el, toEn){
  if (!el || el.nodeType !== 1 || !el.getAttribute) return;
  for (var i=0;i<ATTRS.length;i++){
    var a = ATTRS[i]; if (!el.hasAttribute(a)) continue;
    var store = '__i18n_'+a;
    if (toEn){
      var raw = el.getAttribute(a), key = (raw||'').trim();
      if (key.length < 2 || !HAS_CJK.test(key)) continue;
      var en = ZH2EN[key]; if (en == null) en = patternTranslate(key);
      if (en != null && en !== key){ if (el[store] == null) el[store] = raw; el.setAttribute(a, en); }
    } else if (el[store] != null){ el.setAttribute(a, el[store]); el[store] = null; }
  }
}
function walkText(root, toEn){
  var doc = root.nodeType === 9 ? root : (root.ownerDocument || document);
  var tw = doc.createTreeWalker(root, NodeFilter.SHOW_TEXT, { acceptNode: function(n){ var p=n.parentNode; return (p && SKIP[p.nodeName]) ? NodeFilter.FILTER_REJECT : NodeFilter.FILTER_ACCEPT; } });
  var list = [], n; while ((n = tw.nextNode())) list.push(n);
  for (var i=0;i<list.length;i++) tText(list[i], toEn);
}
function walk(root, toEn){
  if (!root) return;
  if (root.nodeType === 1) tAttrs(root, toEn);
  walkText(root, toEn);
  var scope = root.nodeType === 9 ? root.body : root;
  if (scope && scope.querySelectorAll){ var els = scope.querySelectorAll('[placeholder],[title],[aria-label]'); for (var i=0;i<els.length;i++) tAttrs(els[i], toEn); }
}
var observer = null;
function startObserver(){
  if (observer || !document.body) return;
  observer = new MutationObserver(function(muts){
    if (LANG !== 'en' || applying) return;
    for (var i=0;i<muts.length;i++){
      var m = muts[i];
      if (m.type === 'childList'){ for (var j=0;j<m.addedNodes.length;j++){ var nn = m.addedNodes[j]; if (nn.nodeType===3) tText(nn,true); else if (nn.nodeType===1) walk(nn,true); } }
      else if (m.type === 'characterData' && m.target.nodeType===3) tText(m.target,true);
      else if (m.type === 'attributes' && m.target.nodeType===1) tAttrs(m.target,true);
    }
  });
  observer.observe(document.body, { childList:true, subtree:true, characterData:true, attributes:true, attributeFilter:ATTRS });
}
function stopObserver(){ if (observer){ observer.disconnect(); observer = null; } }
function applyDom(){ applying = true; if (LANG === 'en'){ walk(document, true); startObserver(); } else { stopObserver(); walk(document, false); } applying = false; }

export function setLang(l){
  if (l !== 'zh' && l !== 'en') return;
  LANG = l; localStorage.setItem('kp_lang', l);
  document.documentElement.lang = (l === 'en' ? 'en' : 'zh-Hant');
  if (DICT['meta.title']) document.title = t('meta.title');
  applyDom();
  window.dispatchEvent(new CustomEvent('kp-lang-changed', { detail:{ lang:l } }));
}
function init(){
  document.documentElement.lang = (LANG === 'en' ? 'en' : 'zh-Hant');
  if (DICT['meta.title']) document.title = t('meta.title');
  if (LANG === 'en') applyDom();
}
if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init); else init();
window.PlanAII18n = { t: t, getLang: getLang, setLang: setLang, applyDom: applyDom };
